async (params, browser) => {
  // Open TikTok Explore page
  await browser.open('https://www.tiktok.com/explore')

  // Wait for trending content
  await browser.waitForSelector('[data-e2e="explore-item"], .explore-video-card, div[class*="DivVideoCard"]', 15000)

  // Let page fully render
  await browser.wait(3000)

  // Scroll to load more trending videos
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(2000)

  // Scroll for additional content
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract trending videos
  const trending_data = await browser.evaluate(`const videos = []; const items = document.querySelectorAll('[data-e2e="explore-item"], .explore-video-card, div[class*="DivVideoCardBody"], div[class*="DivWrapper"] > div[class*="DivVideoCard"]'); for (let i = 0; i < Math.min(items.length, 20); i++) { const el = items[i]; const descEl = el.querySelector('[data-e2e="explore-item-desc"], a[title], .card-desc'); const creatorEl = el.querySelector('[data-e2e="explore-item-user-unique-id"], [data-e2e="creator-uniqueid"], .author-uniqueid, p[class*="PAuthorTitle"]'); const viewsEl = el.querySelector('[data-e2e="video-views"], strong.video-count, .view-count, span[class*="SpanCount"]'); const musicEl = el.querySelector('.music-title, [data-e2e="explore-music"]'); const thumbEl = el.querySelector('img[src*="tiktokcdn"], img.poster, picture img'); const linkEl = el.querySelector('a[href*="/video/"], a[href*="/@"]'); videos.push({ description: descEl ? (descEl.getAttribute('title') || descEl.textContent.trim()).substring(0, 300) : '', creator: creatorEl ? creatorEl.textContent.trim() : '', views: viewsEl ? viewsEl.textContent.trim() : '', music: musicEl ? musicEl.textContent.trim() : '', thumbnail: thumbEl ? thumbEl.src : '', url: linkEl ? linkEl.href : '' }); } return { trending_count: videos.length, trending_videos: videos }`)

  return trending_data
}
